Anthropic Python SDKOpenAI Python SDK <pre><code>import anthropic

client = anthropic.Anthropic()

# (1) Define tools
tools = [{
    "name": "get_stock_price",
    "description": "Retrieves the current stock price for a given ticker symbol.",
    "input_schema": {
        "type": "object",
        "properties": {
            "ticker": {"type": "string", "description": "The stock ticker, e.g. AAPL"}
        },
        "required": ["ticker"]
    }
}]

# (2) Request completion with tools
message = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    max_tokens=1024,
    tools=tools,
    messages=[{"role": "user", "content": "What is the price of AAPL?"}]
)

# (3) Process the tool_use content block
print(message.content)
</code></pre> <pre><code>from openai import OpenAI

client = OpenAI()

# (1) Define functions
tools = [{
    "type": "function",
    "function": {
        "name": "get_weather",
        "description": "Get the current weather",
        "parameters": {
            "type": "object",
            "properties": {
                "location": {"type": "string", "description": "The city and state"}
            },
            "required": ["location"]
        }
    }
}]

# (2) Request chat completion
response = client.chat.completions.create(
    model="gpt-4o",
    messages=[{"role": "user", "content": "What's the weather in London?"}],
    tools=tools
)

# (3) Access tool_calls from the message
print(response.choices[0].message.tool_calls)
</code></pre>

TypeScriptPython <pre><code>import { BeeAgent } from "beeai-framework/agents/bee/agent";
import { UnstructuredRawModel } from "beeai-framework/backend/unstructured";
import { DuckDuckGoSearchTool } from "beeai-framework/tools/search/duckduckgo";

async function main() {
    // 1. Create the agent with a tool
    const agent = new BeeAgent({
        llm: new UnstructuredRawModel({ modelId: "gpt-4o" }),
        tools: [new DuckDuckGoSearchTool()],
        memory: []
    });

    // 2. Run a query
    const response = await agent.run({ prompt: "What is the Bee Agent Framework?" });
    console.log(response.result.text);
}

main();
</code></pre> <pre><code>from beeai_framework.agents.bee.agent import BeeAgent
